const badgeVariants = [
  (name: string) => `Verified ${name.replace(' Developers', '').replace(' Engineers', '').replace(' Specialists', '')} Expert`,
  (name: string) => `Top ${name.replace(' Developers', '').replace(' Engineers', '').replace(' Specialists', '')} Talent`,
  (name: string) => `Vetted ${name.replace(' Developers', '').replace(' Engineers', '').replace(' Specialists', '')} Pro`,
];

// Template profiles generator — now with category-specific variation
function generateProfiles(name: string, skills: string[]): ProfileData[] {
  const sub = subcategories[Object.keys(subcategories).find(k => subcategories[k].name === name) || ''];
  const parentCategory = sub?.parentCategory || 'Other';
  const hash = simpleHash(name);

  const idx1 = hash % profilePool.length;
  const idx2 = (hash + 5) % profilePool.length;
  const p1 = profilePool[idx1];
  const p2 = profilePool[idx2 === idx1 ? (idx2 + 1) % profilePool.length : idx2];

  const avatarNum1 = (hash + idx1) % 100;
  const avatarNum2 = (hash + idx2 + 50) % 100;

  const bios = bioTemplatesByCategory[parentCategory] || bioTemplatesByCategory['Other'];
  const bio1 = bios[hash % bios.length];
  const bio2 = bios[(hash + 2) % bios.length];

  const badge1 = badgeVariants[hash % badgeVariants.length];
  const badge2 = badgeVariants[(hash + 1) % badgeVariants.length];

  const skillSet1 = skills.slice(0, 7);
  const skillSet2 = [...skills.slice(2), ...skills.slice(0, 2)].slice(0, 7);

  return [
    {
      name: p1.name,
      location: p1.location,
      badge: badge1(name),
      bio: bio1(name, skills),
      skills: skillSet1,
      availability: p1.availability,
      previousCompany: p1.company,
      avatar: `https://randomuser.me/api/portraits/${p1.gender}/${avatarNum1}.jpg`,
    },
    {
      name: p2.name,
      location: p2.location,
      badge: badge2(name),
      bio: bio2(name, skills),
      skills: skillSet2,
      availability: p2.availability,
      previousCompany: p2.company,
      avatar: `https://randomuser.me/api/portraits/${p2.gender}/${avatarNum2}.jpg`,
    },
  ];
}
