// ====== Helper Functions ======

export function getSubcategoryBySlug(slug: string): DeveloperSubcategory | undefined {
  return subcategories[slug];
}

export function getAllSubcategorySlugs(): string[] {
  return Object.keys(subcategories);
}

export function getAllSubcategories(): DeveloperSubcategory[] {
  return Object.values(subcategories);
}

export function getSubcategoriesByCategory(category: string): DeveloperSubcategory[] {
  return Object.values(subcategories).filter(s => s.parentCategory === category);
}

export function getRelatedSubcategories(slug: string, limit: number = 8): DeveloperSubcategory[] {
  const sub = subcategories[slug];
  if (!sub) return [];
  return sub.relatedSlugs
    .map(s => subcategories[s])
    .filter(Boolean)
    .slice(0, limit);
}

